body.script:
//
    /*
      CONFIGURACAO GLOBAL DA DATA DO EVENTO
      Altere somente a constante abaixo para atualizar todos os contadores e textos de data do site.
      Use o formato ISO com fuso de Recife/Brasilia: YYYY-MM-DDTHH:mm:ss-03:00
      Exemplo de preenchimento: AAAA-MM-DDTHH:mm:ss-03:00
    */
    const EVENT_DATE_ISO = "2026-09-18T18:00:00-03:00";

    const header = document.querySelector(".site-header");
    const revealTargets = document.querySelectorAll(".section-title, .stat, .photo-tile, .track-card, .tabs, .gallery-shell, .cta, .sponsor-tier, .ticket-card, .included");
    const counters = document.querySelectorAll("[data-count]");
    const galleryMain = document.querySelector("#galleryMain");
    const galleryTitle = document.querySelector("#galleryTitle");
    const galleryText = document.querySelector("#galleryText");
    const prevPhoto = document.querySelector("#prevPhoto");
    const nextPhoto = document.querySelector("#nextPhoto");
    const eventDateLabels = document.querySelectorAll("[data-event-date-label]");
    const countdownEls = {
      days: document.querySelector("#countDays"),
      hours: document.querySelector("#countHours"),
      minutes: document.querySelector("#countMinutes"),
      seconds: document.querySelector("#countSeconds"),
      note: document.querySelector("#countdownNote")
    };
    const ticketCountdownEls = {
      days: document.querySelector("#ticketCountDays"),
      hours: document.querySelector("#ticketCountHours"),
      minutes: document.querySelector("#ticketCountMinutes"),
      seconds: document.querySelector("#ticketCountSeconds"),
      note: document.querySelector("#ticketCountdownNote")
    };
    const countdownDisplays = [countdownEls, ticketCountdownEls];

    const gallery = [
      {
        title: "Edição 2017",
        text: "Comunidade, mentorias e validação em ritmo intenso durante as 54 horas de imersão.",
