      },
      {
        title: "Edição 2018",
        text: "Do problema ao MVP: decisões rápidas, testes reais e evolução contínua.",
        image: "https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEhP74IMkUl0UA9hVeatJ06s1kBOWuu2XW90zv2E24pwlkA3iRHT4UOMcogSMC4YlABbctp0TQmv6GRYxGW5leBcR2JGrPh8PGueNqC76P__bf4JGsc4OLmRbzFcqtsMfHNzTSZSisNuimpI00Uwmw4w8eRtEqY7yWAK2nZHc8jOnzJV-94yR-b967dkd1QH/s1944/2018-1.jpg",
        tint: "linear-gradient(135deg, rgba(255,98,89,.32), rgba(8,24,38,.48))"
      },
      {
        title: "Edição 2019 - Times",
        text: "Construção colaborativa, iteração constante e preparação para o pitch final.",
        image: "https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEi4_R-Lqg98smqSMfzvt7Nra_gj9pAYfQDoJDbq_TVrah3lH-F92Xw4hL1uU7qinWjVTFo-uzU0V8x95-N7_ZTDUtQEQPvgDSArHgroRlnXa5vE91B72-JYbAoy6QBpkpkQxR_WsDt5F1-g6aGfEyxE4PgICn6tB4idvz_pbq9V2OOBNQLuPBr1kC4QWDgg/s960/2019-1.jpg",
        tint: "linear-gradient(135deg, rgba(0,166,178,.28), rgba(8,24,38,.42))"
      },
      {
        title: "Edição 2019 - Final",
        text: "Apresentações para banca, feedback qualificado e celebração das melhores soluções.",
        image: "https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEjESwh0kisqKsrtW2xTvTBaVnO-fLwhXwxy_sNNXOKbIa1DHSpS4MnJ7FhOQqw__Y6R8b687kcwJEfMxoGcOGKpIyd1lDNqT05WhWZGVL7NcxDoA7dYXvXMe_1z6CRMOWc4afrZo9VtZ3n1IIdsQIcnMw8CxKUDP-NuWvjXv5zgRNfuvUSPWxAPw17PJrVw/s2048/2019-2.jpg",
        tint: "linear-gradient(135deg, rgba(238,111,45,.26), rgba(8,24,38,.46))"
      }
    ];

    let galleryIndex = 0;

    const setHeaderState = () => {
      header.classList.toggle("is-scrolled", window.scrollY > 18);
    };

    const setPointerGlow = (event) => {
      document.body.style.setProperty("--mx", `${event.clientX}px`);
      document.body.style.setProperty("--my", `${event.clientY}px`);
    };

    const animateCounter = (el) => {
      if (el.dataset.done === "true") return;
      el.dataset.done = "true";

      const target = Number(el.dataset.count);
      const suffix = el.dataset.suffix || "";
      const duration = 1200;
      const start = performance.now();

      const tick = (now) => {
        const progress = Math.min((now - start) / duration, 1);
        const eased = 1 - Math.pow(1 - progress, 3);
        el.textContent = Math.round(target * eased) + suffix;
        if (progress < 1) requestAnimationFrame(tick);
      };

      requestAnimationFrame(tick);
    };

    const setGallery = (index) => {
      galleryIndex = (index + gallery.length) % gallery.length;
      const item = gallery[galleryIndex];
      galleryMain.style.backgroundImage = `${item.tint}, url('${item.image}')`;
      galleryTitle.textContent = item.title;
      galleryText.textContent = item.text;
    };

    const padCountdown = (value) => String(value).padStart(2, "0");

    const setCountdownValues = (target, days, hours, minutes, seconds, note) => {
      if (!target.days || !target.hours || !target.minutes || !target.seconds) return;

      target.days.textContent = days;
      target.hours.textContent = hours;
      target.minutes.textContent = minutes;
      target.seconds.textContent = seconds;
      if (target.note && note) target.note.textContent = note;
    };

    const setEventDateLabels = (label) => {
      eventDateLabels.forEach((dateLabel) => {
        dateLabel.textContent = label;
      });
    };

    const normalizeBloggerPath = (value) => {
      try {
        return new URL(value, window.location.href).pathname.replace(/\/$/, "");
      } catch (error) {
        return "";
      }
    };

    const slugifyBloggerText = (value) => {
      return String(value || "")
        .normalize("NFD")
        .replace(/[\u0300-\u036f]/g, "")
        .toLowerCase()
        .replace(/[^a-z0-9]+/g, "-")
        .replace(/^-+|-+$/g, "");
    };

    const getBloggerEntryLink = (entry) => {
      const links = entry.link || [];
      const alternate = links.find((link) => link.rel === "alternate");
      return alternate ? alternate.href : "";
    };

    const getBloggerEntries = async (feedUrl) => {
      const response = await fetch(feedUrl, { credentials: "same-origin" });
      if (!response.ok) throw new Error(`Feed indisponivel: ${feedUrl}`);
      const data = await response.json();
      return data.feed && data.feed.entry ? data.feed.entry : [];
    };

    const loadBloggerPageContent = async () => {
      const page = document.querySelector("[data-blogger-page]");
      const titleTarget = document.querySelector("#bloggerPageTitle");
      const bodyTarget = document.querySelector("#bloggerPageBody");
      if (!page || !bodyTarget) return;

      const currentPath = normalizeBloggerPath(window.location.href);
      const currentSlug = currentPath.split("/").pop().replace(/\.html$/, "");
      const titleHint = titleTarget ? slugifyBloggerText(titleTarget.textContent) : "";
      const feeds = [
        "/feeds/pages/default?alt=json&max-results=150",
        "/feeds/posts/default?alt=json&max-results=150"
      ];

      try {
        for (const feed of feeds) {
          const entries = await getBloggerEntries(feed);
          const match = entries.find((entry) => {
            const entryPath = normalizeBloggerPath(getBloggerEntryLink(entry));
            const entryTitle = entry.title && entry.title.$t ? entry.title.$t : "";
            const entrySlug = slugifyBloggerText(entryTitle);
            return entryPath === currentPath || entryPath.endsWith(`/${currentSlug}.html`) || entrySlug === currentSlug || entrySlug === titleHint;
          });

          if (match) {
            const title = match.title && match.title.$t ? match.title.$t : "";
            const content = match.content && match.content.$t ? match.content.$t : "";
            if (titleTarget && title) titleTarget.textContent = title;
            bodyTarget.innerHTML = content || "<p>Conteudo indisponivel para esta pagina.</p>";
            page.classList.add("is-loaded");
            return;
          }
        }

        bodyTarget.innerHTML = "<p>Nao foi possivel encontrar o conteudo desta pagina no feed do Blogger.</p>";
      } catch (error) {
        bodyTarget.innerHTML = "<p>Nao foi possivel carregar o conteudo desta pagina agora.</p>";
      }
    };

    const updateCountdown = () => {
      if (!EVENT_DATE_ISO) {
        setEventDateLabels("Data em breve");
        countdownDisplays.forEach((display) => {
          setCountdownValues(display, "--", "--", "--", "--", "Aguardando divulgação da data oficial.");
        });
        return;
      }

      const eventDate = new Date(EVENT_DATE_ISO);

      if (Number.isNaN(eventDate.getTime())) {
        setEventDateLabels("Data inválida");
        countdownDisplays.forEach((display) => {
          setCountdownValues(display, "--", "--", "--", "--", "Configure uma data válida no HTML.");
        });
        return;
      }

      const formattedDate = new Intl.DateTimeFormat("pt-BR").format(eventDate);
      setEventDateLabels(formattedDate);

      const distance = eventDate.getTime() - Date.now();

      if (distance <= 0) {
        countdownDisplays.forEach((display) => {
          setCountdownValues(display, "00", "00", "00", "00", "Evento em andamento ou encerrado.");
        });
        return;
      }

      const day = 24 * 60 * 60 * 1000;
      const hour = 60 * 60 * 1000;
      const minute = 60 * 1000;
      const days = Math.floor(distance / day);
      const hours = Math.floor((distance % day) / hour);
      const minutes = Math.floor((distance % hour) / minute);
      const seconds = Math.floor((distance % minute) / 1000);

      countdownDisplays.forEach((display) => {
        setCountdownValues(display, String(days), padCountdown(hours), padCountdown(minutes), padCountdown(seconds), "Até a abertura do evento.");
      });
    };

    revealTargets.forEach((item, index) => {
      item.classList.add("reveal");
      item.style.transitionDelay = `${Math.min(index % 4, 3) * 70}ms`;
    });

    const observer = new IntersectionObserver((entries) => {
      entries.forEach((entry) => {
        if (!entry.isIntersecting) return;
        entry.target.classList.add("is-visible");

        if (entry.target.matches(".stat")) {
          const counter = entry.target.querySelector("[data-count]");
          if (counter) animateCounter(counter);
        }
      });
    }, { threshold: .16 });

    revealTargets.forEach((item) => observer.observe(item));
    if (prevPhoto) prevPhoto.addEventListener("click", () => setGallery(galleryIndex - 1));
    if (nextPhoto) nextPhoto.addEventListener("click", () => setGallery(galleryIndex + 1));

    setHeaderState();
    if (galleryMain && galleryTitle && galleryText) setGallery(0);
    loadBloggerPageContent();
    updateCountdown();
    if (EVENT_DATE_ISO) setInterval(updateCountdown, 1000);
    window.addEventListener("scroll", setHeaderState, { passive: true });
    window.addEventListener("pointermove", setPointerGlow, { passive: true });
//
